function autoFormatTime(k){let M=k['value']['replace'](/\D/g,'');switch(M['length']>0x4&&(M=M['slice'](0x0,0x4)),M['length']){case 0x0:case 0x1:case 0x2:k['value']=M;break;case 0x3:if(parseInt(M['slice'](0x0,0x2),0xa)<=0x17)k['value']=M['slice'](0x0,0x2)+':'+M['slice'](0x2);else{let O=M['slice'](0x0,0x1)['padStart'](0x2,'0'),T=M['slice'](0x1);k['value']=O+':'+T;}break;case 0x4:let q=M['slice'](0x0,0x2),v=M['slice'](0x2);k['value']=q+':'+v;}}function transformTimeValue(k){let M=k['trim']();if(/^\d{2}$/['test'](M))return M[0x0]['padStart'](0x2,'0')+':'+M[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](M))return 0x3===M['length']?parseInt(M['slice'](0x0,0x2),0xa)<=0x17?M['slice'](0x0,0x2)+':'+M['slice'](0x2):M['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+M['slice'](0x1):M['slice'](0x0,0x2)+':'+M['slice'](0x2);if(M['includes'](':')){let [q,v]=M['split'](':');return v||(v='00'),q=q['padStart'](0x2,'0'),v=v['padStart'](0x2,'0'),q+':'+v;}return M;}